6764→func ValidateSecret(secret *core.Secret) field.ErrorList {
  6765→	allErrs := ValidateObjectMeta(&secret.ObjectMeta, true, ValidateSecretName, field.NewPath("metadata"))
  6766→
  6767→	dataPath := field.NewPath("data")
  6768→	totalSize := 0
  6769→	for key, value := range secret.Data {
  6770→		for _, msg := range validation.IsConfigMapKey(key) {
  6771→			allErrs = append(allErrs, field.Invalid(dataPath.Key(key), key, msg))
  6772→		}
  6773→		totalSize += len(value)
  6774→	}
  6775→	if totalSize > core.MaxSecretSize {
  6776→		allErrs = append(allErrs, field.TooLong(dataPath, "" /*unused*/, core.MaxSecretSize))
  6777→	}
  6778→
  6779→	switch secret.Type {
  6780→	case core.SecretTypeServiceAccountToken:
  6781→		// Only require Annotations[kubernetes.io/service-account.name]
  6782→		// Additional fields (like Annotations[kubernetes.io/service-account.uid] and Data[token]) might be contributed later by a controller loop
  6783→		if value := secret.Annotations[core.ServiceAccountNameKey]; len(value) == 0 {
  6784→			allErrs = append(allErrs, field.Required(field.NewPath("metadata", "annotations").Key(core.ServiceAccountNameKey), ""))
  6785→		}
  6786→	case core.SecretTypeOpaque, "":
  6787→	// no-op
  6788→	case core.SecretTypeDockercfg:
  6789→		dockercfgBytes, exists := secret.Data[core.DockerConfigKey]
  6790→		if !exists {
  6791→			allErrs = append(allErrs, field.Required(dataPath.Key(core.DockerConfigKey), ""))
  6792→			break
  6793→		}
  6794→
  6795→		// make sure that the content is well-formed json.
  6796→		if err := json.Unmarshal(dockercfgBytes, &map[string]interface{}{}); err != nil {
  6797→			allErrs = append(allErrs, field.Invalid(dataPath.Key(core.DockerConfigKey), "<secret contents redacted>", err.Error()))
  6798→		}
  6799→	case core.SecretTypeDockerConfigJSON:
  6800→		dockerConfigJSONBytes, exists := secret.Data[core.DockerConfigJSONKey]
  6801→		if !exists {
  6802→			allErrs = append(allErrs, field.Required(dataPath.Key(core.DockerConfigJSONKey), ""))
  6803→			break
  6804→		}
  6805→
  6806→		// make sure that the content is well-formed json.
  6807→		if err := json.Unmarshal(dockerConfigJSONBytes, &map[string]interface{}{}); err != nil {
  6808→			allErrs = append(allErrs, field.Invalid(dataPath.Key(core.DockerConfigJSONKey), "<secret contents redacted>", err.Error()))
  6809→		}
  6810→	case core.SecretTypeBasicAuth:
  6811→		_, usernameFieldExists := secret.Data[core.BasicAuthUsernameKey]
  6812→		_, passwordFieldExists := secret.Data[core.BasicAuthPasswordKey]
  6813→
  6814→		// username or password might be empty, but the field must be present
  6815→		if !usernameFieldExists && !passwordFieldExists {
  6816→			allErrs = append(allErrs, field.Required(dataPath.Key(core.BasicAuthUsernameKey), ""))
  6817→			allErrs = append(allErrs, field.Required(dataPath.Key(core.BasicAuthPasswordKey), ""))
