   101→func getConfigMapNames(pod *v1.Pod) sets.Set[string] {
   102→	result := sets.New[string]()
   103→	podutil.VisitPodConfigmapNames(pod, func(name string) bool {
   104→		result.Insert(name)
   105→		return true
