   102→func getSecretNames(pod *v1.Pod) sets.Set[string] {
   103→	result := sets.New[string]()
   104→	podutil.VisitPodSecretNames(pod, func(name string) bool {
   105→		result.Insert(name)
   106→		return true
   107→	})
   108→	return result
   109→}
